"""
MKT Christ in Every Verse — Romans chapters 8–10
Run: python3 scripts/zc-christ-romans-8-10.py

Source data used:
- data/translation/draft/mediating/romans.json (MKT text)
- data/commentary/mkt-christ/romans.json (ch.1-7 for style/terminology continuity)

Key decisions in this range:
- Ch.8: extraordinarily dense with direct Christological content (Spirit of Christ,
  co-heirs with Christ, conformed to the image of the Son, Christ at the right hand);
  most verses in ch.8 are classified "direct" because Christ is the named subject.
- Ch.9: the Christological content is primarily typological (election-before-merit,
  potter/clay sovereignty) and two direct statements (9:5 Christ as God over all,
  9:33 Christ as the cornerstone); transitional/narrative verses use shadow or theme.
- Ch.10: multiple direct statements (10:4 Christ as telos, 10:9 Jesus is Lord,
  10:13 calling on the Lord = calling on Christ); the OT citations Paul weaves in
  are applied Christologically and classified accordingly.
- Continuity from ch.4-7: directness levels stated as "A direct:", "A type:",
  "A shadow:", "A theme:", "A revelation of God:".
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ROMANS = {
  "8": {
    "1": '<p>A direct: "There is now no condemnation for those who are in Christ Jesus." The verse states the Christological conclusion of the entire argument from 1:18 through 7:25: the condemnation that sin deserved and that the law pronounced has been removed by Christ\'s atoning work (3:24-26; 8:3). The location "in Christ Jesus" is the sphere in which the verdict stands.</p>',
    "2": '<p>A direct: The law of the Spirit of life "in Christ Jesus" has set free from the law of sin and death. The liberation is specifically located in union with Christ; the Spirit who liberates is the "Spirit of Christ" (v.9) — the Spirit given because Christ\'s atoning work opened the way for the Spirit\'s full indwelling of God\'s people (cf. Ezek 36:26-27 fulfilled through Christ).</p>',
    "3": '<p>A direct: "God did this by sending his own Son in the likeness of sinful flesh and as a sin offering, and so he condemned sin in the flesh." The two movements — sending the Son and condemning sin through him — express the Incarnation and the Atonement as a single divine act. The "sin offering" language (peri hamartias) places Christ\'s death in continuity with the Levitical system it fulfills and surpasses.</p>',
    "4": '<p>A direct: The Spirit enables "the righteous requirement of the law" to be "fully met in us." The law\'s demand — what no human could satisfy — is satisfied in Christ (who kept it perfectly) and is fulfilled in those who are in Christ through the Spirit\'s enabling work. Christ\'s fulfilment of the law is not its abolition but its eschatological completion.</p>',
    "5": '<p>A theme: The two orientations (flesh and Spirit) correspond to two ways of living that lead to different ends. Christ\'s death and resurrection established the new orientation as possible; the Spirit\'s presence is the marker of those who live according to the Spirit. The two-ways theme runs from Ps 1 through Deut 30 to here, now defined Christologically.</p>',
    "6": '<p>A theme: The mind governed by the Spirit brings life and peace. The "life and peace" that the Spirit-orientation produces is the eschatological shalom that Christ\'s resurrection secured (5:1 peace with God; 8:11 bodily resurrection). The Spirit-governed life is the present experience of what Christ accomplished.</p>',
    "7": '<p>A revelation of God: The flesh is "hostile to God" and "does not submit to God\'s law." The depth of the enmity that Christ was sent to overcome (5:10 "we were God\'s enemies... reconciled through the death of his Son") is here named in its full character: structural, constitutional hostility. The magnitude of the Incarnation and Atonement is commensurate with the depth of this enmity.</p>',
    "8": '<p>A theme: Those in the realm of the flesh "cannot please God." The impossibility of pleasing God from within the flesh-domain grounds the necessity of the Spirit\'s work, which itself is made possible by Christ\'s atonement. The law\'s failure (8:3) and the flesh\'s inability (8:8) converge to establish why "sending the Son" was the only solution.</p>',
    "9": '<p>A direct: "You... are not in the realm of the flesh but are in the realm of the Spirit, if indeed the Spirit of God lives in you. And if anyone does not have the Spirit of Christ, they do not belong to Christ." The equation of "Spirit of God" and "Spirit of Christ" is a high Christological claim: the Spirit who is God\'s is equally Christ\'s. Belonging to Christ is defined by Spirit-possession.</p>',
    "10": '<p>A direct: "But if Christ is in you, then even though your body is subject to death because of sin, the Spirit gives life because of righteousness." The indwelling Christ and the indwelling Spirit are coextensive in Paul\'s theology; Christ in you means the Spirit in you means life. The present death-of-the-body and the life-of-the-Spirit is the eschatological tension the resurrection will finally resolve.</p>',
    "11": '<p>A direct: "If the Spirit of him who raised Jesus from the dead is living in you, he who raised Christ from the dead will also give life to your mortal bodies through his Spirit." The resurrection of Christ is the guarantor and pattern of the believer\'s resurrection. The God who raised Jesus will raise us — through the same Spirit who is already present as the firstfruits of the full harvest (8:23).</p>',
    "12": '<p>A theme: The obligation not to live according to the flesh is the ethical corollary of Christ\'s death and resurrection. The one who died with Christ and was raised with Christ (ch.6) owes nothing to the flesh-principle; that debt was paid in Christ\'s death. The obligation is now entirely to the Spirit, who is Christ\'s own Spirit (v.9).</p>',
    "13": '<p>A direct: "But if by the Spirit you put to death the misdeeds of the body, you will live." The mortification Paul commends is not ascetic self-effort but Spirit-empowered participation in the death-and-resurrection of Christ (6:6). The Spirit who raised Christ (v.11) also empowers the putting-to-death of sin.</p>',
    "14": '<p>A direct: "Those who are led by the Spirit of God are the children of God." The Spirit\'s leading is the mark of divine sonship — which is the sonship that believers share with Christ, the Son par excellence. Being led by the Spirit is participating in Christ\'s own filial relationship with the Father.</p>',
    "15": '<p>A direct: "The Spirit you received brought about your adoption to sonship. And by him we cry, \'Abba, Father.\'" The adoption (huiothesia) is into the same filial relationship Christ has with the Father. The cry "Abba, Father" is the prayer-language that characterizes Jesus\'s own intimacy with God (Mark 14:36); the Spirit enables believers to participate in Christ\'s own address of the Father.</p>',
    "16": '<p>A direct: "The Spirit himself testifies with our spirit that we are God\'s children." The Spirit\'s testimony is corroboration of the sonship that Christ\'s atoning work secured; the certainty of adoption rests not on the believer\'s subjective sense but on the Spirit\'s objective witness. It is Christ\'s accomplished work, not our spiritual performance, that grounds the testimony.</p>',
    "17": '<p>A direct: "Now if we are children, then we are heirs — heirs of God and co-heirs with Christ." The co-heirship is participation in what belongs to the Son; the inheritance is Christ\'s own inheritance distributed to those who are in him. "If indeed we share in his sufferings in order that we may also share in his glory" — the sharing of Christ\'s glory comes through sharing his suffering-path (Isa 53; Phil 3:10-11).</p>',
    "18": '<p>A direct: "I consider that our present sufferings are not worth comparing with the glory that will be revealed in us." The glory to be revealed is the glory of God\'s children (v.19) — which is the glory of conformation to Christ\'s image (v.29). Present suffering is the path Christ walked before us; the glory beyond it is the destination he entered at his resurrection.</p>',
    "19": '<p>A direct: Creation waits in eager expectation "for the children of God to be revealed." The revelation of God\'s children is their glorification — their public manifestation as those conformed to the image of the Son (v.29). The entire created order is oriented toward the completion of God\'s redemptive work in Christ, since creation\'s own liberation depends on it (v.21).</p>',
    "20": '<p>A shadow: Creation was subjected to futility not by its own choice but by God\'s judicial decree in response to Adam\'s sin (Gen 3:17-19). The subjection is temporary: it is paired with hope (v.20b). The curse that Christ reversed for humanity (5:12-21) will ultimately be reversed for creation as well (v.21). The shadow of creation\'s bondage points toward the liberation Christ\'s resurrection inaugurated.</p>',
    "21": '<p>A direct: "The creation itself will be liberated from its bondage to decay and brought into the freedom and glory of the children of God." The new creation (Isa 65:17; Rev 21:5) is the extension of Christ\'s resurrection-work to the entire created order. Christ is the firstborn of the new creation (Col 1:15, 18); what began in his resurrection will be completed in the cosmic renewal when he is fully revealed.</p>',
    "22": '<p>A theme: "The whole creation has been groaning as in the pains of childbirth right up to the present time." The childbirth metaphor implies purposive, productive suffering: the pain precedes and causes the arrival of new life. Creation\'s groaning is not random misery but the labor-pain of the new creation that Christ\'s resurrection has set in motion.</p>',
    "23": '<p>A direct: "We ourselves, who have the firstfruits of the Spirit, groan inwardly as we wait eagerly for our adoption to sonship, the redemption of our bodies." The firstfruits of the Spirit is the down-payment on the full harvest of resurrection (cf. 2 Cor 5:5). The redemption of our bodies is the final phase of the redemption Christ accomplished; the Spirit already present is the guarantee of its completion.</p>',
    "24": '<p>A theme: "In this hope we were saved." Salvation\'s character as hope-for-the-not-yet-seen is the eschatological structure of Christian life between the resurrection and the return. The basis of the hope is Christ\'s resurrection — the event that made the completion of redemption not merely possible but certain.</p>',
    "25": '<p>A theme: Waiting patiently for what is not yet seen is the posture of those who live between Christ\'s resurrection and his return. The patience (hypomonē) Paul commends is the same patient endurance that characterized Christ\'s path through suffering to glory — and the path Paul commended to Abraham\'s children (4:18-20).</p>',
    "26": '<p>A direct: "The Spirit helps us in our weakness. We do not know what we ought to pray for, but the Spirit himself intercedes for us through wordless groans." The Spirit\'s intercession alongside Christ\'s intercession (v.34) is the double advocacy that surrounds the believer. The Spirit prays from within; Christ prays from the right hand of God (v.34) — both on the believer\'s behalf.</p>',
    "27": '<p>A direct: "He who searches our hearts knows the mind of the Spirit, because the Spirit intercedes for God\'s people in accordance with the will of God." The Spirit\'s intercession is aligned with the Father\'s will — just as Christ\'s intercession is in accordance with his completed atoning work. Both intercessions are grounded in the same divine purpose.</p>',
    "28": '<p>A direct: "In all things God works for the good of those who love him, who have been called according to his purpose." The calling "according to his purpose" is the calling into the golden chain that follows; the good toward which all things work is specifically defined in v.29 as conformation to Christ\'s image. All of life\'s experiences are instruments of Christoformation.</p>',
    "29": '<p>A direct: "Those God foreknew he also predestined to be conformed to the image of his Son, that he might be the firstborn among many brothers and sisters." The goal of predestination is explicitly Christological: to be conformed to the image of the Son. Christ is the firstborn — the eldest brother who defines what the family will look like. The entire soteriological chain serves this one telos: the image of the Son restored in many.</p>',
    "30": '<p>A direct: "Those he predestined, he also called; those he called, he also justified; those he justified, he also glorified." The golden chain is entirely grounded in Christ\'s work: justification through his blood (5:9), glorification through his resurrection (8:17). The proleptic aorist "glorified" treats the outcome as certain because it rests on Christ\'s accomplished redemption, not human perseverance.</p>',
    "31": '<p>A direct: "If God is for us, who can be against us?" The question rests on the entire argument of chs.3-8: God\'s justifying, Spirit-giving, and co-glorifying action in Christ establishes divine advocacy that no creaturely opposition can nullify. The "for us" is not generic divine goodwill but the specific advocacy demonstrated in the cross and resurrection.</p>',
    "32": '<p>A direct: "He who did not spare his own Son, but gave him up for us all — how will he not also, along with him, graciously give us all things?" The Father\'s gift of the Son is the supreme demonstration of the magnitude of divine giving. The a fortiori argument: if God gave the Son (the infinitely precious), all other gifts are a lesser matter. The cross is the guarantee of all subsequent grace.</p>',
    "33": '<p>A direct: "Who will bring any charge against those whom God has chosen? It is God who justifies." The courtroom scene: no accusation can stick because the Judge has declared acquittal. The justification is God\'s own act in Christ — the basis on which charges cannot succeed. Isaiah\'s vindicated Servant (Isa 50:8-9) is fulfilled in every believer in whom the same God acts.</p>',
    "34": '<p>A direct: "Christ Jesus who died — more than that, who was raised to life — is at the right hand of God and is also interceding for us." The risen, exalted, interceding Christ is Paul\'s complete portrait of the living Lord who secures the believer\'s standing. The death, resurrection, session, and intercession are presented as a single inseparable fact: this is who Christ is, and this is why nothing can condemn those who are in him.</p>',
    "35": '<p>A direct: "Who shall separate us from the love of Christ?" The love of Christ is the operative ground of the inseparability; not a general divine benevolence but the love that expressed itself in the cross (5:8). The catalog of potential separators (trouble, hardship, persecution, famine, nakedness, danger, sword) cannot sever what was forged in the death of the Son.</p>',
    "36": '<p>A direct: Paul quotes Ps 44:22 — "For your sake we face death all day long; we are considered as sheep to be slaughtered" — as Scripture\'s own description of the community\'s suffering for Christ. The community suffers for the name of the one through whose name they are more than conquerors (v.37). The psalm\'s lament is answered not by the removal of suffering but by the resurrection-logic of ch.6.</p>',
    "37": '<p>A direct: "In all these things we are more than conquerors through him who loved us." The conquest comes through Christ, not despite suffering but through it — as Christ himself became the firstborn from the dead through death (Col 1:18). The surplus-victory (<em>hypernikōmen</em>) is the fruit of participation in the one who said "take heart, I have overcome the world" (John 16:33).</p>',
    "38": '<p>A direct: The comprehensive list — death, life, angels, demons, present, future, powers — cannot separate from the love of God in Christ Jesus. The comprehensiveness of the claim reflects the comprehensiveness of Christ\'s victory: his resurrection declared him Lord over every domain in the catalog (Phil 2:10-11). Nothing within creation lies outside his reign.</p>',
    "39": '<p>A direct: "Neither height nor depth, nor anything else in all creation, will be able to separate us from the love of God that is in Christ Jesus our Lord." The climactic statement locates God\'s love in Christ Jesus: it is not a general attribute but the love that came to expression in the specific person and work of the Lord Jesus. The letter\'s central argument — the righteousness of God disclosed in the gospel — arrives here as unbreakable love.</p>'
  },
  "9": {
    "1": '<p>A theme: Paul\'s anguish for Israel, expressed in the strongest terms, reflects his understanding of God\'s own pathos over the unbelief of his covenant people. The Christological significance: Paul\'s grief is that Israel has stumbled over the Messiah (9:32-33) — the one whose coming was the fulfillment of all their privileges.</p>',
    "2": '<p>A theme: The unceasing anguish for his kindred reflects the pastoral heart that Paul shares with Christ, who wept over Jerusalem (Luke 19:41). Paul\'s sorrow is not merely ethnic sentiment but the grief of one who knows what Israel is missing in rejecting the Messiah.</p>',
    "3": '<p>A type: Paul\'s willingness to be "accursed from Christ" for Israel\'s sake echoes Moses\'s offer to be blotted out from God\'s book for Israel (Exod 32:32). Both stand in the shadow of Christ\'s actual bearing of the curse (Gal 3:13) for those who were under it; Paul\'s hypothetical impossibility reflects the real possibility Christ accomplished.</p>',
    "4": '<p>A direct: Israel\'s privileges — adoption, glory, covenants, law, worship, promises — are the accumulated heritage of the covenant-line through which "the Messiah" came (v.5). These privileges are not separate from Christ but preparatory for him; they are the scaffolding that produced and pointed toward the Son of David who is God over all.</p>',
    "5": '<p>A direct: "Theirs are the patriarchs, and from them is traced the human ancestry of the Messiah, who is God over all, forever praised!" The climax of the list of Israel\'s privileges is the Messiah himself — and Paul identifies him as simultaneously of human Davidic ancestry and as "God over all, forever praised." The Christological confession is the highest claim Paul makes for Jesus anywhere in Romans.</p>',
    "6": '<p>A theme: "Not all who are descended from Israel are Israel." The principle that covenant membership is defined by divine election rather than ethnic descent anticipates the gospel\'s offer to all who believe, Jew and Gentile alike. The same God who distinguished within Abraham\'s physical offspring (Isaac, not Ishmael) now distinguishes within ethnic Israel those who receive the Messiah.</p>',
    "7": '<p>A type: "Not because they are his descendants are they all Abraham\'s children." The principle of promise-children over flesh-children (amplified in 4:11-18) established the pattern for the inclusion of all who share Abraham\'s faith in the resurrection-God. Those who trust in the raised Christ are the true seed.</p>',
    "8": '<p>A type: "The children of the promise are regarded as Abraham\'s offspring." The promise-principle that defined Isaac\'s birth over Ishmael\'s is the structural anticipation of the gospel principle: children of God are those born not of blood but of the divine creative word — born again through Christ (cf. John 1:12-13).</p>',
    "9": '<p>A type: God\'s promise — "At the appointed time I will return, and Sarah will have a son" — is the paradigm of divine creative speech producing what natural processes cannot. The resurrection of Christ from death is the supreme instance of this same creative-word power: God speaking life into what was dead, fulfilling the promise "for the dead and calls things into being" (4:17).</p>',
    "10": '<p>A type: Rebekah\'s twins in the womb — differentiated before any human action — is the OT narrative that most clearly establishes the pre-merit character of divine election. The same God who differentiated Jacob and Esau before birth differentiated those who would receive and those who would reject the Messiah.</p>',
    "11": '<p>A type: "In order that God\'s purpose in election might stand: not by works but by him who calls." Election by calling rather than by merit is the OT principle (established in the Jacob/Esau story and throughout the patriarchal narratives) that the gospel enacts on a universal scale. Christ is both the one through whom God calls and the one whose call does not depend on the called person\'s prior merit.</p>',
    "12": '<p>A type: "The older will serve the younger" — God\'s election reverses natural priority. This reversal is the pattern of the gospel: the weak before the wise (1 Cor 1:27), the Gentiles before the proud (10:19-20), the ungodly justified (4:5). Christ himself is the ultimate reversal: the last who was first, the dying who conquered.</p>',
    "13": '<p>A shadow: "Jacob I loved, but Esau I hated" — God\'s sovereign differentiation within the same family is the shadow of the differentiation the gospel produces: some receive the Messiah, others stumble over him (9:32-33). The differentiation is not arbitrary but serves the larger purposes of mercy that Paul will expound in 11:30-32.</p>',
    "14": '<p>A revelation of God: "Is God unjust? Not at all!" Paul defends God\'s righteousness against the charge of arbitrariness. The justice of God in sovereign election is not revealed until it reaches its Christological conclusion (ch.11): through Israel\'s hardening, Gentiles are included; through Gentile fullness, Israel is provoked to receive its own Messiah. The justice of the plan is seen in its totality.</p>',
    "15": '<p>A revelation of God: "I will have mercy on whom I have mercy, and I will have compassion on whom I have compassion." The sovereignty of divine mercy is the OT foundation for the gospel\'s proclamation that God justifies the ungodly (4:5). The mercy that Christ\'s atoning work makes possible is sovereignly bestowed, not earned — which is why it is truly mercy rather than reward.</p>',
    "16": '<p>A revelation of God: "It does not, therefore, depend on human desire or effort, but on God\'s mercy." The absolute priority of divine mercy over human striving grounds the gospel\'s irreducible grace. Christ\'s righteousness is given, not generated; received, not achieved. The non-dependence on human effort is not a discouragement to seek God but a disclosure that mercy is available to the one who cannot deserve it.</p>',
    "17": '<p>A shadow: Pharaoh as the vessel raised up for the display of God\'s power anticipates the way Christ\'s enemies (including Rome and the Jewish leadership) unwittingly served the divine plan of redemption. The cross — the intended instrument of Jesus\'s defeat — became the display of God\'s power (1 Cor 1:24). The power displayed through Pharaoh\'s resistance is the shadow of the power displayed through the resurrection.</p>',
    "18": '<p>A revelation of God: "God has mercy on whom he wants to have mercy, and he hardens whom he wants to harden." The same sovereign will that chose to show mercy through Christ (5:8) also hardens those who resist. The hardening serves the larger mercy: Israel\'s hardening opens the way for Gentile inclusion (11:11-12), and Gentile fullness provokes Israel\'s jealousy toward its own Messiah.</p>',
    "19": '<p>A revelation of God: "Then why does God still blame us? For who is able to resist his will?" The objection Paul voices is the same question that faces the cross: why does God judge the world if the outcome was predetermined? Paul\'s answer (vv.20-21) points to the creator\'s right over the creature — a right that the Incarnation itself enacts: God taking on humanity to redeem it.</p>',
    "20": '<p>A revelation of God: "Who are you, a human being, to talk back to God?" The humility Paul requires before divine sovereignty is not the silencing of questions but the recognition of creaturely limits. The Incarnation is the supreme case of the Creator entering the creature\'s domain — not to dominate but to redeem, which makes the divine prerogative simultaneously awesome and gracious.</p>',
    "21": '<p>A type: The potter\'s right to shape the clay as he sees fit is the type of God\'s sovereign prerogative over his creation. The "vessel for honor" that God shapes for his glory is Christ himself — the one who is the "image of the invisible God" (Col 1:15) — and those who are in him, being conformed to his image (8:29).</p>',
    "22": '<p>A shadow: God bearing with vessels of wrath "in great patience" is a shadow of the long-suffering that preceded the cross: "at just the right time" (5:6) God sent his Son. The patience of God in the OT period (3:25 "sins left unpunished") served the revelation of Christ; the bearing-with of those who resist is in service of the same long mercy.</p>',
    "23": '<p>A direct: God made known "the riches of his glory on the objects of his mercy, whom he prepared in advance for glory." The glory to which the vessels of mercy are prepared is the glory of Christ\'s image (8:29-30); the "riches of his glory" is the same phrase Paul uses in Eph 1:18 and Col 1:27 for the indwelling Christ who is "the hope of glory."</p>',
    "24": '<p>A direct: "Even us, whom he also called, not only from the Jews but also from the Gentiles." The called community — Jewish and Gentile believers — are those prepared in advance for glory (v.23). The Gentile inclusion that fulfills Hosea\'s prophecy (vv.25-26) is the fruit of Christ\'s atoning work removing the dividing wall (Eph 2:14-16).</p>',
    "25": '<p>A direct: Hosea\'s "not my people" who become "my people" is cited as the prophetic basis for Gentile inclusion. The re-calling of the not-my-people is accomplished through the gospel of Christ: the name "Lord" into which all are called (10:13) is the name of Jesus, who calls a new people from all nations.</p>',
    "26": '<p>A direct: "In the very place where it was said to them, \'You are not my people,\' there they will be called \'children of the living God.\'" The reversal of "not my people" to "children of the living God" is what Christ\'s atoning work and the Spirit\'s adoption accomplish (8:15). The "living God" who calls them is the God who raised Jesus from the dead.</p>',
    "27": '<p>A theme: Isaiah\'s "only the remnant will be saved" is cited to explain why not all of ethnic Israel receives the Messiah. The remnant principle — God preserving a faithful core within a larger unfaithful group — runs through all the major prophets and is fulfilled in the Jewish believers who do receive Christ (11:5 "a remnant chosen by grace").</p>',
    "28": '<p>A theme: The Lord\'s swift and decisive execution of his word against Israel parallels the decisive execution of judgment that Christ\'s atoning work resolved; the sentence that was pronounced against sin was executed on Christ (8:3 "condemned sin in the flesh") rather than being indefinitely postponed.</p>',
    "29": '<p>A theme: "Unless the Lord Almighty had left us descendants, we would have become like Sodom." The preservation of the seed (sperma) within Israel is the shadow of the preservation of the righteous seed in every generation that culminates in Christ — the "seed of Abraham" (Gal 3:16) through whom blessing comes to all nations.</p>',
    "30": '<p>A direct: "The Gentiles, who did not pursue righteousness, have obtained it, a righteousness that is by faith." The faith-righteousness that Gentiles obtained without pursuing it is the righteousness of God made available in Christ (3:21-22). The Gentile\'s unexpected obtaining of righteousness is the fulfillment of Isa 65:1 (found by those who did not seek) — realized in the Gentile reception of the gospel.</p>',
    "31": '<p>A theme: "Israel, which pursued the law as the way of righteousness, has not attained their goal." The paradox — those who sought righteousness by law missed it; those who weren\'t seeking it received it — exposes the law\'s inability to produce what only Christ can give. Israel\'s failure is not because the law is bad but because law-keeping cannot constitute the righteousness of God that Christ embodies.</p>',
    "32": '<p>A direct: "They stumbled over the stumbling stone." Christ is the stone that Israel stumbled over precisely because he came not as a political deliverer but as a crucified atoning Messiah — the last thing a works-righteousness framework would recognize as God\'s righteousness. The stumbling was predicted (Isa 8:14; 28:16) and is part of the larger sovereign plan (11:11).</p>',
    "33": '<p>A direct: Paul quotes the combined Isa 28:16/8:14 texts: "See, I lay in Zion a stone that causes people to stumble and a rock that makes them fall, and the one who believes in him will never be put to shame." Christ is explicitly the Zion cornerstone — placed by God, causing some to stumble and providing the foundation of salvation for all who believe. The Christological claim is direct and Pauline, not interpretive imposition.</p>'
  },
  "10": {
    "1": '<p>A theme: Paul\'s prayer for Israel\'s salvation presupposes that salvation is available — through the Messiah Israel has rejected. The prayer is itself the fruit of the gospel\'s universal reach: the same Christ through whom Gentiles have been saved (9:30) is the salvation Paul prays Israel will receive.</p>',
    "2": '<p>A theme: Israel\'s "zeal for God" without knowledge describes the tragic condition of those who pursue the things of God but miss the Messiah in whom the things of God are fulfilled. The same zeal directed toward Christ is what Paul himself exemplifies after his conversion (Phil 3:7-9).</p>',
    "3": '<p>A direct: "Since they did not know the righteousness of God and sought to establish their own, they did not submit to God\'s righteousness." The righteousness of God that Israel missed is the righteousness disclosed in Christ (3:21-22). Non-submission to God\'s righteousness in Christ is the specific failure — not moral laxity but refusing the gift of righteousness offered in the gospel.</p>',
    "4": '<p>A direct: "Christ is the culmination of the law so that there may be righteousness for everyone who believes." Christ as the <em>telos</em> of the law is Paul\'s most direct statement that Christ does not oppose the law but fulfills it — achieving what the law aimed at (righteous people before God) in a way the law itself could not accomplish. The universality ("everyone who believes") is the expansion that the law\'s ethnic particularity could not provide.</p>',
    "5": '<p>A direct: Moses\'s "the person who does these things will live by them" (Lev 18:5) is cited as the law\'s own logic — which Christ fulfilled on behalf of those who trust him. The one who "did these things" perfectly is Christ; the life the law promised is given to those who are in him. Paul\'s citation is not a dead-end but a pointer to Christ as the one in whom the law\'s life-promise is realized.</p>',
    "6": '<p>A direct: The "righteousness by faith" speaks through Moses\'s Deut 30 text Christologically: "Do not say in your heart, \'Who will ascend into heaven?\'" — that is, to bring Christ down. The ascent and descent Paul interprets are Christ\'s Incarnation (descending) and the unnecessary repetition of it; the point is that the definitive coming of Christ has already occurred.</p>',
    "7": '<p>A direct: "\'Who will descend into the deep?\'" — that is, to bring Christ up from the dead. The resurrection of Christ is the completed act that no one needs to re-accomplish; the word is near precisely because Christ has already descended into death and been raised. The gospel\'s accessibility depends entirely on the completed work of the incarnate, crucified, and risen Christ.</p>',
    "8": '<p>A direct: "The word is near you; it is in your mouth and in your heart." Paul identifies this near word as the gospel about Christ — the word that is accessible because Christ has already come down and been raised. The nearness of the gospel is grounded in the completed historical events of the Incarnation and Resurrection, not in human effort to reach God.</p>',
    "9": '<p>A direct: "If you declare with your mouth, \'Jesus is Lord,\' and believe in your heart that God raised him from the dead, you will be saved." The confession "Jesus is Lord" is the NT equivalent of the Shema applied to Christ: acknowledging that the one who sits at God\'s right hand (Ps 110:1) is Jesus. Resurrection-faith and lordship-confession are the two components of saving response to the gospel.</p>',
    "10": '<p>A direct: "It is with your heart that you believe and are justified, and it is with your mouth that you profess your faith and are saved." Justification through heart-belief and salvation through mouth-confession are the personal appropriation of what Christ accomplished objectively. The heart and mouth are the human faculties through which the completed work of Christ is received and publicly acknowledged.</p>',
    "11": '<p>A direct: "Anyone who believes in him will never be put to shame" (Isa 28:16 LXX). The Christological reading of the Isaiah cornerstone text is confirmed: the one who trusts in the stone Christ placed in Zion receives the Isaianic promise of vindication. Non-shame at the final judgment is the eschatological outcome of faith in Christ.</p>',
    "12": '<p>A direct: "There is no difference between Jew and Gentile — the same Lord is Lord of all and richly blesses all who call on him." The "same Lord" is the risen Christ, identified as the Lord (<em>kyrios</em>) whom Joel promised would save all who call on his name (v.13). The Shema\'s one God is now confessed as one Lord in Christ, whose lordship removes ethnic barriers.</p>',
    "13": '<p>A direct: "Everyone who calls on the name of the Lord will be saved" (Joel 2:32). Paul has just identified "the Lord" as Jesus Christ (vv.9-12); Joel\'s universal salvation-promise for those who call on YHWH is fulfilled in the gospel\'s proclamation of Jesus\'s lordship. Calling on Christ\'s name is calling on the divine name revealed at the resurrection.</p>',
    "14": '<p>A theme: The chain of hearing, believing, calling, and being sent describes the missionary logic of the gospel. The chain begins with being "sent" — which grounds in Christ\'s own sending of apostles (Matt 28:19-20; John 20:21). The gospel\'s communicability depends on the chain; the chain\'s beginning is Christ\'s commission of those who proclaim him.</p>',
    "15": '<p>A direct: "How beautiful are the feet of those who bring good news" (Isa 52:7). Paul applies the Isaianic herald\'s announcement — "Your God reigns!" — to the gospel preachers who proclaim the risen King. Christ\'s resurrection is the divine reign announced; the beauty of the heralds\' feet is the beauty of the news they carry: the Isaianic expectation of God\'s return to Zion fulfilled in Christ.</p>',
    "16": '<p>A direct: Isaiah\'s "Lord, who has believed our message?" (Isa 53:1) is cited as the prophetic anticipation of gospel rejection. The same Servant Song whose opening verse Paul quotes is the passage that describes Christ\'s atoning death (Isa 53:4-12); the rejected message and the rejected Servant are the same event seen from different angles.</p>',
    "17": '<p>A direct: "Faith comes from hearing the message, and the message is heard through the word about Christ." The message whose reception produces faith is the proclamation of Christ; without this specific word, saving faith cannot exist. The word about Christ is the constitutive content of the gospel — not moral instruction about God in general but the specific announcement of the crucified and risen Christ.</p>',
    "18": '<p>A direct: Paul applies Ps 19:4 (creation\'s universal proclamation) to the gospel\'s universal proclamation. As the sky declares God\'s glory to all the earth without words, so the gospel has been declared to all the earth through the apostolic mission. Christ is the one proclaimed; the Ps 19 comparison elevates the gospel\'s proclamation to cosmic significance.</p>',
    "19": '<p>A direct: Moses predicted that God would provoke Israel to jealousy through "those who are not a nation" (Deut 32:21). Paul\'s Gentile mission is the fulfillment of this prediction: Gentiles receiving the Messiah provokes Israel to reconsider the one they stumbled over (cf. 11:11-14). Christ is the common point — rejected by Israel, received by Gentiles, ultimately the ground of Israel\'s own inclusion.</p>',
    "20": '<p>A direct: Isaiah\'s "I was found by those who did not seek me" (Isa 65:1) describes the Gentile reception of the gospel: God disclosed himself in Christ to those who had no prior covenant claim. The Gentiles\' finding of God in the gospel of Christ fulfills the Isaianic prophecy of the unexpected reach of divine self-revelation.</p>',
    "21": '<p>A direct: "All day long I have held out my hands to a disobedient and obstinate people" (Isa 65:2). God\'s persistent reaching-toward Israel is not merely historical: it is the posture Paul himself embodies as he prays for Israel\'s salvation (10:1). The outstretched hands of God find their ultimate expression in Christ\'s own outstretched hands on the cross — the final and fullest reaching-toward those who resisted him.</p>'
  }
}

def main():
    existing = load_comm('mkt-christ', 'romans')
    merge_comm(existing, ROMANS)
    save_comm('mkt-christ', 'romans', existing)
    print('Romans 8–10 mkt-christ written.')

if __name__ == '__main__':
    main()
